"C:\\WINDOWS\\System32\\WindowsPowerShell\\v1.0\\powershell.exe" -Command "@'
"'$ErrorActionPreference = '"'Stop'

"'$root = '"'demo/_scratch/real-agent-validation'
"'$dailyNotesDir = Join-Path $root '"'workspace/memory/daily-notes'
"'$derivedDir = Join-Path $root '"'workspace/memory/doc/daily-note-derived'
"'$sourceStatePath = Join-Path $root '"'jobs/daily-notes-to-doc/state/runtime-state.json'

"'$requiredFiles = @('"'README.md','current-state.md','decisions.md','open-questions.md','source-map.md')
"'$headings = @{
  '"'current-state.md' = @('## Stable Signals','## Active Workstreams','## Recent Changes','## Coverage')
  'decisions.md' = @('## Active Decisions','## Archived Decisions')
  'open-questions.md' = @('## Open Questions','## Recently Resolved')
  'source-map.md' = @('## Processed Notes','## Coverage Summary')
}
"'$allowedBoilerplate = @('"'No archived decisions yet.','No recently resolved questions yet.')

"'$findings = New-Object System.Collections.Generic.List[string]

$sourceState = Get-Content -Raw $sourceStatePath | ConvertFrom-Json
$processedNotes = @($sourceState.processed_notes)
$processedSet = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::OrdinalIgnoreCase)
foreach ($note in $processedNotes) { [void]$processedSet.Add([string]$note) }

foreach ($file in $requiredFiles) {
  $path = Join-Path $derivedDir $file
  if (-not (Test-Path $path)) {
    $findings.Add("Missing required derived doc: $path")
  }
}

function Get-SectionBlocks {
  param([string]$Content)
  $lines = $Content -split "`r?`n"
  $currentHeading = '"''
  "'$block = New-Object System.Collections.Generic.List[string]
  $blocks = @()
  foreach ($line in $lines) {
    if ($line -match '"'"'^## '"') {
      if ("'$block.Count -gt 0) {
        $blocks += [pscustomobject]@{ Heading = $currentHeading; Lines = @($block) }
        $block = New-Object System.Collections.Generic.List[string]
      }
      $currentHeading = $line.Trim()
      continue
    }
    if ([string]::IsNullOrWhiteSpace($line)) {
      if ($block.Count -gt 0) {
        $blocks += [pscustomobject]@{ Heading = $currentHeading; Lines = @($block) }
        $block = New-Object System.Collections.Generic.List[string]
      }
      continue
    }
    if ($currentHeading -ne '"'') {
      "'$block.Add($line)
    }
  }
  if ($block.Count -gt 0) {
    $blocks += [pscustomobject]@{ Heading = $currentHeading; Lines = @($block) }
  }
  return $blocks
}

$citationTargets = New-Object System.Collections.Generic.List[object]
foreach ($file in @('"'current-state.md','decisions.md','open-questions.md','source-map.md')) {
  "'$path = Join-Path $derivedDir $file
  if (-not (Test-Path $path)) { continue }
  $content = Get-Content -Raw $path
  foreach ($heading in $headings[$file]) {
    if ($content -notmatch [regex]::Escape($heading)) {
      $findings.Add("$file is missing required heading '"'"'$heading'"'.\")
    }
  }

  if ("'$file -in @('"'current-state.md','decisions.md','open-questions.md')) {
    "'$blocks = Get-SectionBlocks -Content $content
    foreach ($entry in $blocks) {
      $trimmedBlock = ($entry.Lines | ForEach-Object { $_.Trim() }) | Where-Object { $_ -ne '"'' }
      if ("'$trimmedBlock.Count -eq 0) { continue }
      if ($trimmedBlock.Count -eq 1 -and $allowedBoilerplate -contains $trimmedBlock[0]) { continue }
      $hasCitation = $false
      foreach ($line in $trimmedBlock) {
        if ($line -like '"'Source notes:*') { "'$hasCitation = $true; break }
      }
      if (-not $hasCitation) {
        $preview = $trimmedBlock[0]
        $findings.Add("$file contains an uncited claim under '"'"'$($entry.Heading)'"': "'$preview")
      }
    }
  }

  $matches = [regex]::Matches($content, '"'Source notes:\\s*((?:\\[["'^'"\\]]+\\]\\(["'^'"\\)]+\\))(?:,\\s*\\[["'^'"\\]]+\\]\\(["'^'"\\)]+\\))*)')
  foreach ("'$match in $matches) {
    $links = [regex]::Matches($match.Groups[1].Value, '"'\\[(["'^'"\\]]+)\\]\\((["'^'"\\)]+)\\)')
    foreach ("'$link in $links) {
      $target = $link.Groups[2].Value
      $resolved = [System.IO.Path]::GetFullPath((Join-Path (Resolve-Path $derivedDir) $target))
      $citationTargets.Add([pscustomobject]@{ File = $file; Target = $target; Resolved = $resolved })
    }
  }
}

foreach ($citation in $citationTargets) {
  if (-not (Test-Path $citation.Resolved)) {
    $findings.Add("$($citation.File) cites a missing daily note path: $($citation.Target)")
  }
}

$sourceMapPath = Join-Path $derivedDir '"'source-map.md'
if (Test-Path "'$sourceMapPath) {
  $sourceMapContent = Get-Content -Raw $sourceMapPath
  $rowMatches = [regex]::Matches($sourceMapContent, '"'"'^'"\\| \\[(["'^'"\\]]+)\\]\\(["'^'"\\)]+\\) \\|', [System.Text.RegularExpressions.RegexOptions]::Multiline)
  "'$rowNotes = @($rowMatches | ForEach-Object { $_.Groups[1].Value })
  $uniqueRowNotes = $rowNotes | Select-Object -Unique
  if ($rowNotes.Count -ne $uniqueRowNotes.Count) {
    $dupes = $rowNotes | Group-Object | Where-Object { $_.Count -gt 1 } | ForEach-Object { $_.Name }
    foreach ($dup in $dupes) {
      $findings.Add("source-map.md contains a duplicate processed-note row for $dup.")
    }
  }
  if ($rowNotes.Count -ne $processedNotes.Count) {
    $findings.Add("source-map.md has $($rowNotes.Count) processed-note rows but source-agent state lists $($processedNotes.Count) processed notes.")
  }
  $max = [Math]::Max($rowNotes.Count, $processedNotes.Count)
  for ($i = 0; $i -lt $max; $i++) {
    $row = if ($i -lt $rowNotes.Count) { $rowNotes[$i] } else { $null }
    $expected = if ($i -lt $processedNotes.Count) { [string]$processedNotes[$i] } else { $null }
    if ($row -ne $expected) {
      $findings.Add("source-map.md note order does not match source-agent processed_notes at position $($i + 1): expected '"'"'$expected'"' but found '"'$row'"'.\")
      break
    }
  }
}

"'$dailyNotes = Get-ChildItem $dailyNotesDir -Filter '"'*.md' | Sort-Object Name | ForEach-Object { [System.IO.Path]::GetFileNameWithoutExtension("'$_.Name) }
$unprocessed = @($dailyNotes | Where-Object { -not $processedSet.Contains($_) })
if ($processedNotes.Count -gt 0) {
  $lastProcessed = [string]$processedNotes[-1]
  $newerUnprocessed = @($unprocessed | Where-Object { $_ -gt $lastProcessed })
} else {
  $newerUnprocessed = $unprocessed
}
foreach ($note in $newerUnprocessed) {
  $findings.Add("Newer unprocessed daily note exists: demo/_scratch/real-agent-validation/workspace/memory/daily-notes/$note.md is present but missing from jobs/daily-notes-to-doc/state/runtime-state.json processed_notes, so the derived docs are stale.")
}

$status = if ($findings.Count -eq 0) { '"'pass' } else { 'fail' }

"'$result = [pscustomobject]@{
  status = $status
  findings = @($findings)
  processed_notes = @($processedNotes)
  source_map_rows = if (Test-Path $sourceMapPath) { @($rowNotes) } else { @() }
  daily_notes = @($dailyNotes)
}
$result | ConvertTo-Json -Depth 6
